var dsDuAn=void 0;async function getJSONDuAn(){await $.getJSON("/assets/json/du-an.json",(function(n){dsDuAn=n}))}async function loadListDuAn(){await getJSONDuAn(),$.each(dsDuAn,(function(n,s){let t=s.status?"Done":"Pending",e=`<span class="px-4 py-0.5 ${s.status?"bg-green-600":"bg-red-600"} mb-1 rounded-lg">${t}</span>`,a=`<button type="button" \n      onclick="updateLuotTruyCap(${s.id}, '${s.project_url}');" \n      class="px-4 py-0.5 bg-blue-600 hover:bg-blue-800 mb-1 \n      rounded-lg ${"#"==s.project_url?"opacity-50 cursor-not-allowed":""}" ${"#"==s.project_url?"disabled":""}>\n      Thử nghiệm\n    </button>`;$("#listDuAn").append(`\n    <div class="bg-white dark:bg-gray-700 p-4 da da-${t} cursor-default da-id-${s.id}">\n  <div class="flex justify-between items-baseline font-semibold text-xs text-black dark:text-white mt-1">\n    <h4 class="text-xl">${s.project_name}</h4>\n    <div class="flex mb-2">\n      <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="currentColor" class="bi bi-eye" viewBox="0 0 16 16">\n        <path d="M16 8s-3-5.5-8-5.5S0 8 0 8s3 5.5 8 5.5S16 8 16 8M1.173 8a13 13 0 0 1 1.66-2.043C4.12 4.668 5.88 3.5 8 3.5s3.879 1.168 5.168 2.457A13 13 0 0 1 14.828 8q-.086.13-.195.288c-.335.48-.83 1.12-1.465 1.755C11.879 11.332 10.119 12.5 8 12.5s-3.879-1.168-5.168-2.457A13 13 0 0 1 1.172 8z" />\n        <path d="M8 5.5a2.5 2.5 0 1 0 0 5 2.5 2.5 0 0 0 0-5M4.5 8a3.5 3.5 0 1 1 7 0 3.5 3.5 0 0 1-7 0" />\n      </svg>\n      <span class="ml-1">${s.viewer}</span>\n    </div>\n  </div>\n  <div class="text-gray-800 text-xs dark:text-gray-200 mt-0.5">\n    <h4 class="text-xs">${s.description}</h4>\n    <div class="mt-1 mb-1">\n    <div class="flex">\n      <span class="mt-2">Nguồn dữ liệu:</span>\n      <a href="${s.ds_url}" class="text-blue-800 dark:text-blue-300 mt-2 ml-1 hover:text-red-600 hover:dark:text-red-400">${s.ds_name}</a>\n    </div>\n    <div class="flex">\n      <span class="mt-2">FE:</span>\n      <span class="mt-2 ml-1 font-semibold">${s.fe}</span>\n    </div>\n    <div class="flex">\n      <span class="mt-2">BE:</span>\n      <span class="mt-2 ml-1 font-semibold">${s.be}</span>\n    </div>\n    <div class="flex">\n      <span class="mt-2">Loại dự án:</span>\n      <span class="mt-2 ml-1 font-semibold">${s.type}</span>\n    </div>\n    <div class="flex">\n      <span class="mt-2">Mã nguồn:</span>\n      <a href="${s.git}" class="text-blue-600 dark:text-blue-300 mt-2 ml-1 hover:text-red-600 hover:dark:text-red-400">GitHub</a>\n    </div>\n    </div>\n    \n  </div>\n  <div class="flex justify-between mt-4 items-end text-white text-xs"> ${e} \n    ${a}\n  </div>\n</div>\n    `)}))}async function updateLuotTruyCap(n,s){await getJSONDuAn(),window.open(s,"_blank")}function hideAllDACard(){$("#daStatus button").removeClass("border-b-4 border-green-500 border-red-500 border-blue-500"),$("#listDuAn .da").hide()}$(document).ready((function(){loadListDuAn(),$("#daStatus button").click((function(){hideAllDACard();let n=$(this).data("da-status"),s=$("#listDuAn");switch(n){case"all":$(this).addClass("border-b-4 border-blue-500"),s.find(".da").show();break;case"pending":$(this).addClass("border-b-4 border-red-500"),s.find(".da-Pending").show();break;case"done":$(this).addClass("border-b-4 border-green-500"),s.find(".da-Done").show()}})),$("#searchBar input").on("keyup",(function(){$("#daStatus button")[0].click();let n=$(this).val().toLowerCase().trim();$("#listDuAn .da").each((function(){$(this).find("h4").text().toLowerCase().includes(n)?$(this).show():$(this).hide()}))}))}));